#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\Users\USER\Desktop\SQLP\node_modules\.pnpm\@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2\node_modules\@astrojs\language-server\bin\node_modules;C:\Users\USER\Desktop\SQLP\node_modules\.pnpm\@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2\node_modules\@astrojs\language-server\node_modules;C:\Users\USER\Desktop\SQLP\node_modules\.pnpm\@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2\node_modules\@astrojs\node_modules;C:\Users\USER\Desktop\SQLP\node_modules\.pnpm\@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2\node_modules;C:\Users\USER\Desktop\SQLP\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/c/Users/USER/Desktop/SQLP/node_modules/.pnpm/@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2/node_modules/@astrojs/language-server/bin/node_modules:/mnt/c/Users/USER/Desktop/SQLP/node_modules/.pnpm/@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2/node_modules/@astrojs/language-server/node_modules:/mnt/c/Users/USER/Desktop/SQLP/node_modules/.pnpm/@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2/node_modules/@astrojs/node_modules:/mnt/c/Users/USER/Desktop/SQLP/node_modules/.pnpm/@astrojs+language-server@2._badb20d964928ef30d5520c172fd04f2/node_modules:/mnt/c/Users/USER/Desktop/SQLP/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../@astrojs/language-server/bin/nodeServer.js" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../@astrojs/language-server/bin/nodeServer.js" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../@astrojs/language-server/bin/nodeServer.js" $args
  } else {
    & "node$exe"  "$basedir/../@astrojs/language-server/bin/nodeServer.js" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
